/**
 * @param {number[]} nums
 * @param {number} digit
 * @return {number}
 */
function solve(nums, digit) {
    let count = 0;
    const digitChar = String(digit);

    for (const num of nums) {
        const numStr = String(num);
        for (const char of numStr) {
            if (char === digitChar) {
                count++;
            }
        }
    }

    return count;
}

